+    function createBaseContext(): AlertContext {
+      return {
+        metrics: {
+          agents: { total: 0, byStatus: {} },
+          tokens: { last24h: 0, quotaUsedPercent: 0 },
+          performance: { avgResponseMs: 0, successRate: 100, errorCount: 0 },
